mapper.select:
SELECT id, location_code, location_name, location_type, region_code, shelf_code, slot_code, warehouse_id, capacity, capacity_unit, used_capacity, temperature_min, temperature_max, humidity_min, humidity_max, sensor_device_id, material_types, status, remark, created_at, updated_at, version FROM wms_location WHERE deleted = 0 AND warehouse_id = #{q.warehouseId}
AND (location_code LIKE CONCAT('%', #{q.keyword}, '%') OR location_name LIKE CONCAT('%', #{q.keyword}, '%'))
AND status = #{q.status}
ORDER BY created_at DESC

SELECT l.id, l.location_code, l.location_name, l.location_type, l.region_code, l.shelf_code, l.slot_code, l.warehouse_id, l.capacity, l.capacity_unit, l.used_capacity, l.temperature_min, l.temperature_max, l.humidity_min, l.humidity_max, l.material_types, l.status, l.remark, l.created_at, l.updated_at, l.version FROM wms_location l INNER JOIN wms_warehouse w ON w.id = l.warehouse_id AND w.deleted = 0 WHERE l.deleted = 0
AND (l.location_code LIKE CONCAT('%', #{q.keyword}, '%') OR l.location_name LIKE CONCAT('%', #{q.keyword}, '%'))
AND l.status = #{q.status}
AND l.warehouse_id = #{q.warehouseId}
AND w.warehouse_name LIKE CONCAT('%', #{q.warehouseName}, '%')
AND w.warehouse_type = #{q.warehouseType}
AND w.org_id = #{q.orgId}
AND w.org_id IN
#{orgId}
AND w.id IS NULL
ORDER BY l.created_at DESC
